INSERT INTO `movies` (`movie_id`, `imdb_id`, `title`, `year`, `genre`, `description`, `actors`, `image_url`, `avg_rating`) VALUES
(3, 'tt3896198', 'Guardians of the Galaxy Vol. 2', 2017, 'Action', 'The Guardians struggle to keep together as a team while dealing with their personal family issues, notably Star-Lord\'s encounter with his father, the ambitious celestial being Ego.', 'Chris Pratt, Zoe Saldaña, Dave Bautista', 'https://m.media-amazon.com/images/M/MV5BNWE5MGI3MDctMmU5Ni00YzI2LWEzMTQtZGIyZDA5MzQzNDBhXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
