(145, 'tt0056592', 'To Kill a Mockingbird', 1962, 'Crime', 'A widowed lawyer in Depression-era Alabama defends a black man against a false rape charge while teaching his young children about the sad reality of prejudice.', 'Gregory Peck, John Megna, Frank Overton', 'https://m.media-amazon.com/images/M/MV5BZTlkYWU4MGEtZmQyYi00OWEzLTgzY2EtYzVjOTEzYzAyNTk1XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(146, 'tt0105695', 'Unforgiven', 1992, 'Drama', 'Retired Old West gunslinger Will Munny reluctantly takes on one last job to avenge an injustice with the help of his old partner and a young would-be gunman calling himself \"The Schofield Kid\".', 'Clint Eastwood, Gene Hackman, Morgan Freeman', 'https://m.media-amazon.com/images/M/MV5BNmZmMzM3YWMtZjg5Yi00M2MxLTg3ZGItNGU4YjQxNDAxM2Q4XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(147, 'tt0051201', 'Witness for the Prosecution', 1957, 'Crime', 'A veteran British barrister must defend his client in a murder trial that has surprise after surprise.', 'Tyrone Power, Marlene Dietrich, Charles Laughton', 'https://m.media-amazon.com/images/M/MV5BNjRhNTQzMzQtMWViMi00ODQ1LTg0MTEtYWE4ZWZlYjM4YjJhXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(148, 'tt0040897', 'The Treasure of the Sierra Madre', 1948, 'Adventure', 'Two down-on-their-luck Americans searching for work in 1920s Mexico convince an old prospector to help them mine for gold in the Sierra Madre Mountains.', 'Humphrey Bogart, Walter Huston, Tim Holt', 'https://m.media-amazon.com/images/M/MV5BOWM1YjFmODEtMWNhMC00YmI1LWI0Y2EtYzg0YTBhZWI4ODE3XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(149, 'tt0116282', 'Fargo', 1996, 'Crime', 'Minnesota car salesman Jerry Lundegaard\'s inept crime falls apart due to his and his henchmen\'s bungling and the persistent police work of the quite pregnant Marge Gunderson.', 'William H. Macy, Frances McDormand, Steve Buscemi', 'https://m.media-amazon.com/images/M/MV5BNjg4MWE0MjEtODFhNy00MjA5LTg5ODktMzgwNWFmZTAwNjBlXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(150, 'tt0042192', 'All About Eve', 1950, 'Drama', 'A seemingly timid but secretly ruthless ingénue insinuates herself into the lives of an aging Broadway star and her circle of theater friends.', 'Bette Davis, Anne Baxter, George Sanders', 'https://m.media-amazon.com/images/M/MV5BMTY2MTAzODI5NV5BMl5BanBnXkFtZTgwMjM4NzQ0MjE@._V1_SX300.jpg', 0.00),
(151, 'tt0476735', 'My Father and My Son', 2005, 'Drama', 'The family of a left-wing journalist is torn apart after the military coup of Turkey in 1980.', 'Çetin Tekindor, Fikret Kuskan, Hümeyra', 'https://m.media-amazon.com/images/M/MV5BZDE3MTBkNmQtNGFjMC00YTcwLWExY2ItN2MyMGZkNWJlMmFmXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(152, 'tt0086250', 'Scarface', 1983, 'Crime', 'In the 1980s, a determined criminal-minded Cuban immigrant becomes the biggest drug smuggler in Miami, and is eventually undone by his own drug addiction.', 'Al Pacino, Michelle Pfeiffer, Steven Bauer', 'https://m.media-amazon.com/images/M/MV5BNDUzYjY0NmUtMDM4OS00Y2Q5LWJiODYtNTk0ZTk0YjZhMTg1XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(153, 'tt0117951', 'Trainspotting', 1996, 'Crime', 'Renton, deeply immersed in the Edinburgh drug scene, tries to clean up and get out despite the allure of drugs and the influence of friends.', 'Ewan McGregor, Ewen Bremner, Jonny Lee Miller', 'https://m.media-amazon.com/images/M/MV5BYmVkNGJkMzQtYWQwOS00OTZmLThjODQtZjNjNzllYzRiNTE0XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(154, 'tt0107207', 'In the Name of the Father', 1993, 'Biography', 'An Irish man\'s coerced confession to an I.R.A. bombing he did not commit results in the imprisonment of his father as well. Meanwhile, a British lawyer fights to clear their names and free them.', 'Daniel Day-Lewis, Pete Postlethwaite, Anthony Brophy', 'https://m.media-amazon.com/images/M/MV5BMGZiZDVjNzYtZWM4ZC00MzVkLThhNDEtMDJlOTBhYzVjMmNhXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(155, 'tt0032551', 'The Grapes of Wrath', 1940, 'Drama', 'An Oklahoma family, driven off their farm by the poverty and hopelessness of the Dust Bowl, joins the westward migration to California, suffering the misfortunes of the homeless in the Great Depression.', 'Henry Fonda, Jane Darwell, John Carradine', 'https://m.media-amazon.com/images/M/MV5BZDgzZjk3OGYtNWI2Ny00MDg3LTgwYWEtNjI1ODAxNjA3ZmFlXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(156, 'tt0021749', 'City Lights', 1931, 'Comedy', 'With the aid of a wealthy erratic tippler, a dewy-eyed tramp who has fallen in love with a blind flower girl accumulates money to be able to help her medically.', 'Charles Chaplin, Virginia Cherrill, Florence Lee', 'https://m.media-amazon.com/images/M/MV5BM2U4NjgzODUtODkyOC00YTE2LTlhNTItYzFlYmM1NTEzZDA2XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(158, 'tt1832382', 'A Separation', 2011, 'Drama', 'A married couple are faced with a difficult decision - to improve the life of their child by moving to another country or to stay in Iran and look after a deteriorating parent who has Alzheimer\'s disease.', 'Payman Maadi, Leila Hatami, Sareh Bayat', 'https://m.media-amazon.com/images/M/MV5BMDM0ZWRmMzctM2M5ZS00ZjU0LWIxN2MtNWNlNGY1ZDhjMDVhXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(159, 'tt0057115', 'The Great Escape', 1963, 'Adventure', 'Allied officers in a German prisoner of war camp during World War II make a daring plan for a mass escape by hundreds of POWs hoping to draw German personnel and resources away from combat operations.', 'Steve McQueen, James Garner, Richard Attenborough', 'https://m.media-amazon.com/images/M/MV5BMDRhNmJjMzEtMWU5MC00YmEyLTg3ZmYtNzYxZTI1ZGU4ZjI1XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(160, 'tt0072890', 'Dog Day Afternoon', 1975, 'Biography', 'Three amateur robbers plan to hold up a Brooklyn bank. A nice, simple robbery: Walk in, take the money, and run. Unfortunately, the supposedly uncomplicated heist suddenly becomes a bizarre nightmare as everything that could go wr...', 'Al Pacino, John Cazale, Penelope Allen', 'https://m.media-amazon.com/images/M/MV5BY2RjNTg2ODMtZWQ4NC00MDdhLWE4MDgtMWFjMjI4ZTIxMGY4XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(163, 'tt0105643', 'Troll 2', 1990, 'Comedy', 'A vacationing family discovers that the entire town they\'re visiting is inhabited by goblins, disguised as humans, who plan to eat them.', 'Michael Paul Stephenson, George Hardy, Margo Prey', 'https://m.media-amazon.com/images/M/MV5BYzJkY2E0ZjEtYjQ4Yy00MmI3LWFhMGItZjllNmJhM2Y5NTBkXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(164, 'tt0046438', 'Tokyo Story', 1953, 'Drama', 'An old couple visit their children and grandchildren in the city, but receive little attention.', 'Chishû Ryû, Chieko Higashiyama, Sô Yamamura', 'https://m.media-amazon.com/images/M/MV5BODdkNzcxZjItMDU2Yy00Y2JlLWFkYTQtNzIwM2Q4MWU5MTU2XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(165, 'tt0048473', 'Pather Panchali', 1955, 'Drama', 'Impoverished priest Harihar Ray, dreaming of a better life for himself and his family, leaves his rural Bengal village in search of work.', 'Kanu Bannerjee, Karuna Bannerjee, Subir Banerjee', 'https://m.media-amazon.com/images/M/MV5BNmZhNzc0ZDMtZDg2My00MjkxLWJjZTctNTljODc2ZjQzMzJkXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(166, 'tt0044741', 'Ikiru', 1952, 'Drama', 'A bureaucrat tries to find meaning in his life after he discovers he has terminal cancer.', 'Takashi Shimura, Nobuo Kaneko, Shin\'ichi Himori', 'https://m.media-amazon.com/images/M/MV5BYWI2MzBhMzItYzQ3OS00N2Q4LTkyZDUtMjM1YTk0NjhkOWRiXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(168, 'tt0405094', 'The Lives of Others', 2006, 'Drama', 'In 1984 East Berlin, an agent of the secret police conducting surveillance on a writer and his lover finds himself becoming increasingly absorbed by their lives.', 'Ulrich Mühe, Martina Gedeck, Sebastian Koch', 'https://m.media-amazon.com/images/M/MV5BYjM1N2Q0YWEtN2E5MC00NDM3LTk2NTEtMTc1NTk5OTA5ZGIzXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(169, 'tt0317705', 'The Incredibles', 2004, 'Animation', 'While trying to lead a quiet suburban life, a family of undercover superheroes are forced into action to save the world.', 'Craig T. Nelson, Samuel L. Jackson, Holly Hunter', 'https://m.media-amazon.com/images/M/MV5BMTY5OTU0OTc2NV5BMl5BanBnXkFtZTcwMzU4MDcyMQ@@._V1_SX300.jpg', 0.00),
(172, 'tt0036868', 'The Best Years of Our Lives', 1946, 'Drama', 'Three traumatized or physically disabled World War II veterans return home to the American Midwest to discover that they and their families have been irreparably changed making readjustment difficult.', 'Myrna Loy, Dana Andrews, Fredric March', 'https://m.media-amazon.com/images/M/MV5BNTgxMzUyODQtMDJmZC00ZGMyLWI3MzAtZTYwYjBjZjFmMzIxXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(174, 'tt0092067', 'Castle in the Sky', 1986, 'Animation', 'Pazu\'s life changes when he meets Sheeta, a girl whom pirates are chasing for her crystal amulet, which has the potential to locate Laputa, a legendary castle floating in the sky.', 'Mayumi Tanaka, Keiko Yokozawa, Kotoe Hatsui', 'https://m.media-amazon.com/images/M/MV5BZjcyMjg2MzktNjg4YS00MjQzLTg0YWQtMjUyZDk2Y2Y0YzZjXkEyXkFqcGc@._V1_SX300.jpg', 0.00);
INSERT INTO `movies` (`movie_id`, `imdb_id`, `title`, `year`, `genre`, `description`, `actors`, `image_url`, `avg_rating`) VALUES
(175, 'tt0112573', 'Braveheart', 1995, 'Biography', 'Scottish warrior William Wallace leads his countrymen in a rebellion to free his homeland from the tyranny of King Edward I of England.', 'Mel Gibson, Sophie Marceau, Patrick McGoohan', 'https://m.media-amazon.com/images/M/MV5BNGMxZDBhNGQtYTZlNi00N2UzLWI4NDEtNmUzNWM2NTdmZDA0XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(176, 'tt0103639', 'Aladdin', 1992, 'Animation', 'A kind-hearted street urchin and a power-hungry Grand Vizier vie for a magic lamp that has the power to make their deepest wishes come true.', 'Scott Weinger, Robin Williams, Linda Larkin', 'https://m.media-amazon.com/images/M/MV5BMmQwYWZjZGItYzc0OC00ZDllLTg3NjItOWIyOWYwMDljMjAyXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(177, 'tt0061512', 'Cool Hand Luke', 1967, 'Crime', 'A laid-back Southern man is sentenced to two years in a rural prison, but refuses to conform.', 'Paul Newman, George Kennedy, Strother Martin', 'https://m.media-amazon.com/images/M/MV5BYzI1NzBkNmMtOWRmMS00YmY2LTk5MjQtZjAzMmIwZDQ2M2UwXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(178, 'tt0097165', 'Dead Poets Society', 1989, 'Comedy', 'Maverick teacher John Keating returns in 1959 to the prestigious New England boys\' boarding school where he was once a star student, using poetry to embolden his pupils to new heights of self-expression.', 'Robin Williams, Robert Sean Leonard, Ethan Hawke', 'https://m.media-amazon.com/images/M/MV5BMDYwNGVlY2ItMWYxMS00YjZiLWE5MTAtYWM5NWQ2ZWJjY2Q3XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(179, 'tt0080678', 'The Elephant Man', 1980, 'Biography', 'A Victorian surgeon rescues a heavily-disfigured and mistreated young man working as a sideshow freak, who gradually reveals his capacity for kindness, intelligence and sophistication.', 'Anthony Hopkins, John Hurt, Anne Bancroft', 'https://m.media-amazon.com/images/M/MV5BMGE3MDZhNmMtMmUxZS00MDJmLTgxYmQtOGU4ODU0Y2JmNDI1XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(183, 'tt0208092', 'Snatch', 2000, 'Comedy', 'Unscrupulous boxing promoters, violent bookmakers, a Russian gangster, incompetent amateur robbers and supposedly Jewish jewelers fight to track down a priceless stolen diamond.', 'Jason Statham, Brad Pitt, Stephen Graham', 'https://m.media-amazon.com/images/M/MV5BYzk5NjJkMTQtN2IyNC00YWM5LTlhZmMtNGI3MWNhMTU1YTc4XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(188, 'tt0087332', 'Ghostbusters', 1984, 'Action', 'Armed with proton packs, four paranormal investigators battle mischievous ghouls in New York.', 'Bill Murray, Dan Aykroyd, Sigourney Weaver', 'https://m.media-amazon.com/images/M/MV5BMGI0Yjg2ODAtNDYzNi00Njc2LTlkMmMtMmRmYWI5MDE4ZGRkXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(191, 'tt0095765', 'Cinema Paradiso', 1988, 'Drama', 'Salvatore, a famous film director, returns to his hometown for the funeral of the local theater\'s film projectionist, Alfredo. He reminisces about his life as a young boy falling in love with cinema.', 'Philippe Noiret, Enzo Cannavale, Antonella Attili', 'https://m.media-amazon.com/images/M/MV5BMTljNzc4YWEtYTZlMS00ODMyLWIwMTAtNWQxY2VkMDEwYTk5XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(194, 'tt0325980', 'Pirates of the Caribbean: The Curse of the Black Pearl', 2003, 'Action', 'Blacksmith Will Turner teams up with eccentric pirate \"Captain\" Jack Sparrow to save Elizabeth Swann, the governor\'s daughter and his love, from Jack\'s former pirate allies, who are now undead.', 'Johnny Depp, Geoffrey Rush, Orlando Bloom', 'https://m.media-amazon.com/images/M/MV5BNDhlMzEyNzItMTA5Mi00YWRhLThlNTktYTQyMTA0MDIyNDEyXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(196, 'tt0435761', 'Toy Story 3', 2010, 'Animation', 'The toys are mistakenly delivered to a day-care center instead of the attic right before Andy leaves for college, and it\'s up to Woody to convince the other toys that they weren\'t abandoned and to return home.', 'Tom Hanks, Tim Allen, Joan Cusack', 'https://m.media-amazon.com/images/M/MV5BMTgxOTY4Mjc0MF5BMl5BanBnXkFtZTcwNTA4MDQyMw@@._V1_SX300.jpg', 0.00),
(198, 'tt0266543', 'Finding Nemo', 2003, 'Animation', 'After his son is captured in the Great Barrier Reef and taken to Sydney, a timid clownfish sets out on a journey to bring him home.', 'Albert Brooks, Ellen DeGeneres, Alexander Gould', 'https://m.media-amazon.com/images/M/MV5BMTc5NjExNTA5OV5BMl5BanBnXkFtZTYwMTQ0ODY2._V1_SX300.jpg', 0.00),
(201, 'tt1130884', 'Shutter Island', 2010, 'Drama', 'Two US marshals are sent to a mental institution on an inhospitable island in order to investigate the disappearance of a patient.', 'Leonardo DiCaprio, Emily Mortimer, Mark Ruffalo', 'https://m.media-amazon.com/images/M/MV5BN2FjNWExYzEtY2YzOC00YjNlLTllMTQtNmIwM2Q1YzBhOWM1XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(203, 'tt2380307', 'Coco', 2017, 'Animation', 'Aspiring musician Miguel, confronted with his family\'s ancestral ban on music, enters the Land of the Dead to find his great-great-grandfather, a legendary singer.', 'Anthony Gonzalez, Gael García Bernal, Benjamin Bratt', 'https://m.media-amazon.com/images/M/MV5BMDIyM2E2NTAtMzlhNy00ZGUxLWI1NjgtZDY5MzhiMDc5NGU3XkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(208, 'tt0096874', 'Back to the Future Part II', 1989, 'Adventure', 'After visiting 2015, Marty McFly must repeat his visit to 1955 to prevent disastrous changes to 1985, without interfering with his first trip.', 'Michael J. Fox, Christopher Lloyd, Lea Thompson', 'https://m.media-amazon.com/images/M/MV5BMTNlOTRmOTEtMTAyMi00NjFiLTk3NDMtNWI0YzA3ZTZlYjZiXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(211, 'tt0264464', 'Catch Me If You Can', 2002, 'Biography', 'Barely 17 yet, Frank is a skilled forger who has passed as a doctor, lawyer and pilot. FBI agent Carl becomes obsessed with tracking down the con man, who only revels in the pursuit.', 'Leonardo DiCaprio, Tom Hanks, Christopher Walken', 'https://m.media-amazon.com/images/M/MV5BMTY5MzYzNjc5NV5BMl5BanBnXkFtZTYwNTUyNTc2._V1_SX300.jpg', 0.00),
(213, 'tt0364569', 'Oldboy', 2003, 'Action', 'After being kidnapped and imprisoned for fifteen years, Oh Dae-Su is released, only to find that he must track down his captor in five days.', 'Choi Min-sik, Yoo Ji-tae, Kang Hye-jeong', 'https://m.media-amazon.com/images/M/MV5BMTAwNzNjYWItZmI0Ni00ZTcyLWIwNWMtZjlmNGMxZTEyYTJmXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(214, 'tt0120338', 'Titanic', 1997, 'Drama', 'A seventeen-year-old aristocrat falls in love with a kind but poor artist aboard the luxurious, ill-fated R.M.S. Titanic.', 'Leonardo DiCaprio, Kate Winslet, Billy Zane', 'https://m.media-amazon.com/images/M/MV5BYzYyN2FiZmUtYWYzMy00MzViLWJkZTMtOGY1ZjgzNWMwN2YxXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(217, 'tt0119488', 'L.A. Confidential', 1997, 'Crime', 'As corruption grows in 1950s Los Angeles, three policemen - one strait-laced, one brutal, and one sleazy - investigate a series of murders with their own brand of justice.', 'Kevin Spacey, Russell Crowe, Guy Pearce', 'https://m.media-amazon.com/images/M/MV5BODdiMjY1OGYtNDk0NC00NGQ1LWI4MDItOTJhMTM0YjE1YTAzXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(218, 'tt0108500', 'The Visitors', 1993, 'Comedy', 'A medieval knight and his servant ask a familiar wizard to move them back in time to prevent father-in-law\'s accidentally killing. Instead, they fly away to the 20th century.', 'Christian Clavier, Jean Reno, Valérie Lemercier', 'https://m.media-amazon.com/images/M/MV5BY2RhYjBlMTMtNTQxZS00ZDI3LWJiZTEtZDRkZGY3NmNhM2VlXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(221, 'tt0177789', 'Galaxy Quest', 1999, 'Adventure', 'The alumni cast of a space opera television series have to play their roles as the real thing when an alien race needs their help. However, they also have to defend both Earth and the alien race from a reptilian warlord.', 'Tim Allen, Sigourney Weaver, Alan Rickman', 'https://m.media-amazon.com/images/M/MV5BZmJkYmNhMGMtMDYyNC00ZDEyLWE2ZjAtYTg5OWViODJlNDdmXkEyXkFqcGc@._V1_SX300.jpg', 0.00),
(229, 'tt0078748', 'Alien', 1979, 'Horror', 'After investigating a mysterious transmission of unknown origin, the crew of a commercial spacecraft encounters a deadly lifeform.', 'Sigourney Weaver, Tom Skerritt, John Hurt', 'https://m.media-amazon.com/images/M/MV5BN2NhMDk2MmEtZDQzOC00MmY5LThhYzAtMDdjZGFjOGZjMjdjXkEyXkFqcGc@._V1_SX300.jpg', 0.00);
